import React, { useEffect, useState, useCallback } from "react";
import Dashboard from "./Dashboard";
import AddTask from "./AddTask";

export default function TaskList() {
  const [tasks, setTasks] = useState([]);
  const [notifications, setNotifications] = useState([]);
  const [showAddModal, setShowAddModal] = useState(false);
  const [deleteId, setDeleteId] = useState(null);

  // 🔥 Toast state
  const [toast, setToast] = useState(null);
  const [toastType, setToastType] = useState("success");
  const [fade, setFade] = useState(false);

  // ✅ Toast function (unchanged logic, only UI improved)
  const showToast = (message, type = "success") => {
    setToast(message);
    setToastType(type);
    setFade(false);

    setTimeout(() => {
      setFade(true);
    }, 2000);

    setTimeout(() => {
      setToast(null);
      setFade(false);
    }, 2500);
  };

  // FETCH DATA
  const fetchAll = useCallback(async () => {
    try {
      const t = await fetch("http://localhost:8086/tasks").then(r => r.json());
      const n = await fetch("http://localhost:8086/tasks/notifications").then(r => r.json());

      setTasks(Array.isArray(t) ? t.filter(x => x?.id) : []);
      setNotifications(Array.isArray(n) ? n : []);
    } catch {
      showToast("Failed to load data", "error");
    }
  }, []);

  useEffect(() => {
    fetchAll();
  }, [fetchAll]);

  // COMPLETE TASK
  const completeTask = async (id) => {
    try {
      await fetch(`http://localhost:8086/tasks/${id}/complete`, { method: "PUT" });

      setTasks(prev =>
        prev.map(t =>
          t?.id === id ? { ...t, completed: true } : t
        )
      );

      showToast("Task completed 🎉", "complete");
    } catch {
      showToast("Failed to complete task", "error");
    }
  };

  // DELETE TASK
  const deleteTask = async () => {
    if (!deleteId) return;

    try {
      await fetch(`http://localhost:8086/tasks/${deleteId}`, {
        method: "DELETE",
      });

      setTasks(prev => prev.filter(t => t?.id !== deleteId));
      setDeleteId(null);

      showToast("Task deleted 🗑️", "delete");
    } catch {
      showToast("Delete failed", "error");
    }
  };

  return (
    <div className="bg-gradient-to-br from-indigo-100 to-purple-200 min-h-screen p-6 font-sans">

      {/* 💎 PREMIUM GLASSY TOAST */}
      {toast && (
        <div
          className={`fixed top-6 left-1/2 -translate-x-1/2 z-50 transition-all duration-700 ease-out
          ${fade ? "opacity-0 -translate-y-6 scale-95" : "opacity-100 translate-y-0 scale-100"}
        `}
        >
          <div
            className={`
              relative overflow-hidden px-6 py-3 rounded-2xl
              backdrop-blur-2xl bg-white/10
              border shadow-2xl text-sm font-medium text-white
              flex items-center gap-3

              ${toastType === "complete" ? "border-green-400/70 shadow-green-400/20" : ""}
              ${toastType === "delete" ? "border-red-400/70 shadow-red-400/20" : ""}
              ${toastType === "success" ? "border-orange-400/70 shadow-orange-400/20" : ""}
              ${toastType === "error" ? "border-red-500 bg-red-500/20 shadow-red-500/20" : ""}
            `}
          >

            {/* ICON */}
            <span className="text-lg">
              {toastType === "complete" && "✅"}
              {toastType === "delete" && "🗑️"}
              {toastType === "success" && "➕"}
              {toastType === "error" && "❌"}
            </span>

            {/* MESSAGE */}
            <span>{toast}</span>

            {/* PROGRESS BAR */}
            <div className="absolute bottom-0 left-0 w-full h-[3px] bg-white/10">
              <div
                className={`
                  h-full animate-toastProgress
                  ${toastType === "complete" ? "bg-green-400" : ""}
                  ${toastType === "delete" ? "bg-red-400" : ""}
                  ${toastType === "success" ? "bg-orange-400" : ""}
                  ${toastType === "error" ? "bg-red-500" : ""}
                `}
              />
            </div>

          </div>
        </div>
      )}

      <Dashboard />

      {/* ADD BUTTON */}
      <div className="flex justify-end mb-6">
        <button
          onClick={() => setShowAddModal(true)}
          className="bg-gradient-to-r from-purple-500 to-indigo-500 text-white px-6 py-3 rounded-2xl shadow-lg hover:scale-105 transition-all duration-300"
        >
          + Add Task
        </button>
      </div>

      {/* ADD MODAL */}
      {showAddModal && (
        <div className="fixed inset-0 bg-black/50 backdrop-blur-sm flex justify-center items-center z-50">
          <AddTask
            closeModal={() => setShowAddModal(false)}
            onTaskAdded={(newTask) => {
              if (newTask?.id) {
                setTasks(prev => [...prev, newTask]);
              }

              showToast("Task added successfully ✨", "success");
              setShowAddModal(false);
            }}
          />
        </div>
      )}

      {/* DELETE MODAL */}
      {deleteId && (
        <div className="fixed inset-0 bg-black/50 backdrop-blur-sm flex justify-center items-center z-50">
          <div className="bg-white/20 backdrop-blur-xl border border-white/30 p-6 rounded-2xl shadow-2xl w-[350px] text-center">

            <h2 className="text-xl font-semibold text-white mb-3">
              Delete Task?
            </h2>

            <p className="text-gray-200 mb-6">
              This action cannot be undone.
            </p>

            <div className="flex justify-center gap-4">
              <button
                onClick={() => setDeleteId(null)}
                className="px-4 py-2 rounded-lg bg-white/30 hover:bg-white/40 text-black"
              >
                Cancel
              </button>

              <button
                onClick={deleteTask}
                className="px-4 py-2 rounded-lg bg-red-500 hover:bg-red-600 text-white"
              >
                Delete
              </button>
            </div>
          </div>
        </div>
      )}

      {/* TASK CARDS */}
      <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-6">

        {tasks.filter(t => t && t.id).map(t => (
          <div
            key={t.id}
            className={`p-6 rounded-2xl shadow-xl transition-all duration-300 hover:scale-[1.03] ${
              t?.completed ? "bg-gray-200/70" : "bg-white/70 backdrop-blur-md"
            }`}
          >
            <div className="flex justify-between items-start">

              <div>
                <h3 className="text-lg font-semibold text-gray-800">
                  {t?.title}
                </h3>
                <p className="text-xs text-gray-500 mt-1">
                  {t?.priority} • {t?.dueDate}
                </p>
              </div>

              <div className="flex items-center gap-2">

                {!t?.completed && (
                  <button
                    onClick={() => completeTask(t.id)}
                    className="text-green-600 hover:bg-green-100 px-3 py-1.5 rounded-md text-sm transition"
                  >
                    Complete ✓
                  </button>
                )}

                <button
                  onClick={() => setDeleteId(t.id)}
                  className="text-red-500 hover:bg-red-100 px-3 py-1.5 rounded-md text-sm transition"
                >
                  Delete ✕
                </button>

              </div>
            </div>

            {t?.completed && (
              <div className="mt-4 text-green-700 font-semibold">
                Completed ✅
              </div>
            )}
          </div>
        ))}
      </div>

      {/* NOTIFICATIONS */}
      {notifications.length > 0 && (
        <div className="mt-10">
          <h2 className="text-2xl font-bold text-gray-700 mb-4">
            Notifications
          </h2>

          <ul className="space-y-2">
            {notifications.map(n => (
              <li
                key={n.id}
                className="p-4 bg-white/70 backdrop-blur-md rounded-xl shadow hover:shadow-lg transition"
              >
                {n.message}
              </li>
            ))}
          </ul>
        </div>
      )}
    </div>
  );
}
